$(function() {
    $(document).on('click', '#mainSidebarToggle', function(event) {
        event.preventDefault();
        if (window.matchMedia('(min-width: 992px)').matches) {
            $('body.leftmenu').toggleClass('main-sidebar-hide');
        } else {
            $('body.leftmenu').toggleClass('main-sidebar-show');
            $('body.leftmenu').removeClass('main-sidebar-hide');
        }
    });
});

$(document).ready(function() {
    $('#setpProcess').val('1');
    $(".form-control").keyup(function() {
        let actNbtn = $(this).attr('id');
		if(actNbtn!='usrPass')
		{
        	$('#' + actNbtn).addClass('parsley-success').removeClass('parsley-error');
        	$('#eR' + actNbtn).fadeOut('slow');
		}
    });

    $(".btnActn").click(function() {
        let actNbtn = $(this).attr('id');
        if (actNbtn == 'createStp') {
            if (isCheck('setpProcess') == '1') {
                $('#dbInfor').hide();
                $('#crtDb').show();
                $('#dbs').addClass('arActive');
                $('#setpProcess').val('2');
                $('#createStp').html('<i class="ti-pencil-alt"></i> Create Database');
            } else if (isCheck('setpProcess') == '2') {
                let isCheckUrl = isCheck('base_url');
                $.post(isCheckUrl, { mysqlHost: isCheck('mysqlHost'), databaseName: isCheck('databaseName'), databaseUser: isCheck('databaseUser'), databasePass: isCheck('databasePass') }, function(htmlAmi) {
                    isNull('mysqlHost');isNull('databaseName');isNull('databaseUser');isNull('databasePass');
                    if (htmlAmi.adClass == 'tst_success') {
                        toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                        $('#setpProcess').val(htmlAmi.stepUp);
                        $('#crtDb').hide();
                        $('#crtSprUsr').show();
                        $('#instl').addClass('arActive');
                        $('#createStp').html('<i class="ti-pencil-alt"></i> Create User');
                    } else if (htmlAmi.adClass == 'tst_warning') { toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon); } else { toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon); }
                }, 'json');
            } else if (isCheck('setpProcess') == '3') {
                let isCheckUrl = isCheck('base_url') + '/create';
                $.post(isCheckUrl, { adminUsr: isCheck('adminUsr'), pass: isCheck('pass'), cnfPass: isCheck('cnfPass') }, function(htmlAmi) {
                    isNull('adminUsr');
                    isNull('pass');
                    isNull('cnfPass');
                    if (htmlAmi.adClass == 'tst_success') {
                        toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                        $('#setpProcess').val(htmlAmi.stepUp);
                        $('#createStp').html('<i class="si si-check"></i> Finish');
                        $('#crtSprUsr').hide();
                        $('#amiFinish').show();
                        $('#fnsh').addClass('arActive');
                        $('#base_url').val(htmlAmi.target);
                    } else if (htmlAmi.adClass == 'tst_warning') { toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon); } else { toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon); }
                }, 'json');
            } else if (isCheck('setpProcess') == '4') { window.location.href = isCheck('base_url'); }
        } else if (actNbtn == 'authenticate') {
            let target = $('#target').html();
            $('#authenticate').html('<i class="fe fe-settings bx-spin"></i> Please Wait...');
            $.post(target, { emailID: isCheck('emailID'), usrPass: isCheck('usrPass') }, function(htmlAmi) {
                if (htmlAmi.adClass == 'tst_success') {
                    toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                    $('#authenticate').html('<i class="si si-login"></i> Sign In');
                    window.location.href = htmlAmi.target;
                } else if (htmlAmi.adClass == 'tst_warning') {
                    toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                    $('#authenticate').html('<i class="si si-login"></i> Sign In');
                } else {
                    toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                    $('#authenticate').html('<i class="si si-login"></i> Sign In');
                }
                isNull('emailID');
                isNull('usrPass');
            }, 'json');
        } else if (actNbtn == 'unlock_period') {
            //isNull('liKey');
            $('#unlock_period').html('<i class="fe fe-settings bx-spin"></i> Please Wait...');
            let target = $('#target').html();
            $.post(target, { liKey: isCheck('liKey') }, function(htmlAmi) {
                if (htmlAmi.adClass == 'tst_success') {
                    toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                    window.location.href = htmlAmi.target;
                    $('#unlock_period').html('Unlock');
                } else if (htmlAmi.adClass == 'tst_warning') {
                    toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                    isError('2', 'liKey');
                    $('#unlock_period').html('Unlock');
                } else {
                    toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                    isError('1', 'liKey');
                    $('#unlock_period').html('Unlock');
                }
            }, 'json');
        } else if (actNbtn == 'forgot_pass') {
            $("#actnAmiMark").html('Reset Your Password');
            $("#login_panel").hide();
            $("#reset_password").show();
        } else if (actNbtn == 'signIn') {
            $("#actnAmiMark").html('Sign In Your Account');
            $("#reset_password").hide();
            $("#login_panel").show();
        } else if (actNbtn == 'resetYrPs') {
            if (!isCheck('register_email')) {
                let msg = ['Please input registered email id'];
                isNull('register_email');
                toastMultiShow('tst_danger', msg, '<i class="fe fe-settings bx-spin"></i>');
            } else {
                let target = $('#targetReset').html();
                $('#resetYrPs').html('<i class="fe fe-settings bx-spin"></i> Please Wait...');
                $.post(target, { emailID: isCheck('register_email') }, function(htmlAmi) {
                    isNull('register_email');
                    if (htmlAmi.adClass == 'tst_success') {
                        toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                        $('#resetYrPs').html('Request reset link');
                        //window.location.href=htmlAmi.target;
                        //$('#register_email').val('');$("#actnAmiMark").html('Sign In Your Account');$("#reset_password").hide();$("#login_panel").show();
                    } else if (htmlAmi.adClass == 'tst_warning') {
                        $('#register_email').removeClass('parsley-success').addClass(htmlAmi.inptErr);
                        toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                        $('#resetYrPs').html('Request reset link');

                    } else {
                        $('#register_email').removeClass('parsley-success parsley-warning').addClass(htmlAmi.inptErr);
                        toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                        $('#resetYrPs').html('Request reset link');
                    }
                }, 'json');
            }
        } else if (actNbtn == 'createPass') {
            if (!isCheck('password')) {
                let msg = ['Please input new password.'];
                isNull('password');
                toastMultiShow('tst_danger', msg, '<i class="fe fe-settings bx-spin"></i>');
            } else if (!isCheck('cnfPassword')) {
                let msg = ['Please input confirm password.'];
                isNull('cnfPassword');
                toastMultiShow('tst_danger', msg, '<i class="fe fe-settings bx-spin"></i>');
            } else if (isCheck('password') != isCheck('cnfPassword')) {
                let msg = ['Oops confirm password is not match with new password'];
                isNull('cnfPassword');
                toastMultiShow('tst_danger', msg, '<i class="fe fe-settings bx-spin"></i>');
                $('#cnfPassword,#password').removeClass('parsley-success').addClass('parsley-warning');
            } else {
                $('#cnfPassword,#password').addClass('parsley-success').removeClass('parsley-warning parsley-error');
                btnOutClass('btn-outline-dark', actNbtn);
                $('#createPass').html('<i class="fe fe-settings bx-spin"></i> Please Wait...');
                let target = $('#target').html();
                $.post(target, { password: isCheck('password'), cnfPassword: isCheck('cnfPassword') }, function(htmlAmi) {
                    if (htmlAmi.adClass == 'tst_success') {
                        toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                        $('#createPass').html('<i class="si si-note"></i> Reset Password');
                        btnOutClass('btn-outline-secondary', actNbtn);
                        setTimeout(function() { window.location.href = htmlAmi.target; }, 2000);
                    } else if (htmlAmi.adClass == 'tst_warning') {
                        $('#cnfPassword,#password').removeClass('parsley-success').addClass(htmlAmi.inptErr);
                        toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                        $('#createPass').html('<i class="si si-note"></i> Reset Password');
                        btnOutClass('btn-outline-secondary', actNbtn);
                    } else {
                        $('#cnfPassword,#password').removeClass('parsley-success parsley-warning').addClass(htmlAmi.inptErr);
                        toastMultiShow(htmlAmi.adClass, htmlAmi.msg, htmlAmi.icon);
                        $('#createPass').html('<i class="si si-note"></i> Reset Password');
                        btnOutClass('btn-outline-secondary', actNbtn);
                    }
                }, 'json');





            }
        }


    });
});

function isCheck(str) { var inputBx = $('#' + str).val(); if (inputBx == "") { return ''; } else { return inputBx; } }

function toastMultiShow(adCls, msg, icon) {
    let valid = '';
    let myClass = "tst_success tst_warning tst_danger";
    let restCls = myClass.replace(adCls, " ");
    let addonMsg = '';
    $.each(msg, function(i, item) { valid += '<li>' + item + '</li>'; });
    $('.tst_danger') /*.addClass('ts_dan')*/ ;
    $('.tst_warning').addClass('ts_war');
    if (adCls == 'tst_success') { addonMsg = icon + ' <ul>' + valid + '</ul>'; } else if (adCls == 'tst_danger') { addonMsg = icon + ' <ul>' + valid + '</ul>'; } else if (adCls == 'tst_warning') { addonMsg = icon + ' <ul>' + valid + '</ul>'; }
    $('.ami_toast').css('visibility', 'visible').html(addonMsg).addClass(adCls).removeClass(restCls);
    setTimeout(function() { $('.ami_toast').css('visibility', 'hidden') }, 2000);
}

function isNull(str) { let inputBx = $('#' + str).val(); if (inputBx == "") { $('#' + str).addClass('parsley-error').removeClass('parsley-success').focus(); } else { $('#' + str).addClass('parsley-success').removeClass('parsley-error').focus(); } }

function isError(str, id) { if (str == "1") { $('#' + id).addClass('parsley-error').removeClass('parsley-success parsley-warning').focus(); } else if (str == "2") { $('#' + id).addClass('parsley-warning').removeClass('parsley-success parsley-error').focus(); } else { $('#' + id).addClass('parsley-success').removeClass('parsley-error parsley-warning').focus(); } }

function btnOutClass(crntCls, crntBtn) {
    let myClass = "btn-outline-primary btn-outline-secondary btn-outline-light btn-outline-dark btn-outline-success btn-outline-danger btn-outline-info btn-outline-warning";
    let restCls = myClass.replace(crntCls, " ");
    $('#' + crntBtn).addClass(crntCls).removeClass(restCls);
}

